const period = $json.period;
const now = DateTime.now().setZone('Europe/Berlin');
let currentStart, currentEnd, previousStart, previousEnd, yoyStart, yoyEnd;
let periodLabel, subjectSuffix, unit;

if (period === 'weekly') {
  // letzte vollständige Kalenderwoche (Mo–So) in Europe/Berlin
  const thisMonday = now.startOf('week');
  const cs = thisMonday.minus({ weeks: 1 });
  const ce = cs.plus({ weeks: 1 }).minus({ milliseconds: 1 });
  currentStart = cs.toISO();
  currentEnd = ce.toISO();
  previousStart = cs.minus({ weeks: 1 }).toISO();
  previousEnd = cs.minus({ milliseconds: 1 }).toISO();
  yoyStart = cs.minus({ years: 1 }).toISO();
  yoyEnd = ce.minus({ years: 1 }).toISO();
  periodLabel = `Wochenreport KW${cs.weekNumber} / ${cs.weekYear}`;
  subjectSuffix = `KW${cs.weekNumber} ${cs.weekYear}`;
  unit = 'day';
} else {
  // letzter vollständiger Kalendermonat
  const cs = now.minus({ months: 1 }).startOf('month');
  const ce = cs.endOf('month');
  currentStart = cs.toISO();
  currentEnd = ce.toISO();
  const ps = cs.minus({ months: 1 });
  previousStart = ps.toISO();
  previousEnd = ps.endOf('month').toISO();
  yoyStart = cs.minus({ years: 1 }).toISO();
  yoyEnd = cs.minus({ years: 1 }).endOf('month').toISO();
  const monthName = cs.setLocale('de').toFormat('LLLL yyyy');
  periodLabel = `Monatsreport ${monthName}`;
  subjectSuffix = monthName;
  unit = 'day';
}

return [{ json: { period, periodLabel, subjectSuffix, currentStart, currentEnd, previousStart, previousEnd, yoyStart, yoyEnd, unit, timezone: 'Europe/Berlin' } }];

