// Defensive cleanup: strip evtl. geleakte Tool-Use-Narration und Markdown-Fences,
// die schwächere Modelle in den sichtbaren Output schreiben würden.
let raw = ($input.first().json.output ?? '').toString();
raw = raw.replace(/Calling\s+[A-Za-z0-9_]+\s+with input:\s*\{[^{}]*\}\s*/g, '');
raw = raw.replace(/^\s*Calling\s+[A-Za-z0-9_]+.*$/gm, '');
raw = raw.replace(/```html\s*/gi, '').replace(/```\s*$/g, '');
raw = raw.replace(/^\s*Hier ist[^\n]*\n/i, '');
const startTags = ['<table', '<!doctype', '<!DOCTYPE', '<html'];
const positions = startTags.map((t) => raw.indexOf(t)).filter((i) => i >= 0);
if (positions.length > 0) raw = raw.slice(Math.min(...positions));
raw = raw.replace(/\n{3,}/g, '\n\n').trim();

const ctx = $('Compute Period').first().json;
return [{ json: { html: raw, subjectSuffix: ctx.subjectSuffix, periodLabel: ctx.periodLabel } }];
